standardize_demographics <- function(df, demo_map) {
  #' Standardize demographic columns for weighting.
  #'
  #' Takes a data frame and a named list mapping canonical names to actual column

  #' names (as produced by get_demo_cols in precompute_weights.R or manually).
  #' Adds region, age_num, age_group, and female_wt columns.
  #'
  #' @param df Data frame with raw demographic columns
  #' @param demo_map Named list: canonical name -> actual column name.
  #'   Expected keys: "province", "age", "gender"/"gender1"/"female".
  #'   Attention check keys should be prefixed with "attn__".
  #' @return Data frame with added region, age_num, age_group, female_wt columns
  if (nrow(df) == 0) return(df)

  # Province -> region
  prov_col <- demo_map[["province"]]
  if (!is.null(prov_col) && prov_col %in% names(df)) {
    prov_vals <- df[[prov_col]]
    prov_num <- suppressWarnings(as.numeric(prov_vals))
    text_match <- province_text_map[as.character(prov_vals)]
    df$region <- province_to_region(ifelse(is.na(prov_num), text_match, prov_num))
  } else {
    df$region <- NA_character_
  }

  # Age -> age_group
  age_col <- demo_map[["age"]]
  if (!is.null(age_col) && age_col %in% names(df)) {
    df$age_num <- suppressWarnings(as.numeric(df[[age_col]]))
    df$age_group <- dplyr::case_when(
      df$age_num <= 34 ~ 1L,
      df$age_num <= 54 ~ 2L,
      df$age_num >= 55 ~ 3L,
      TRUE ~ NA_integer_
    )
  } else {
    df$age_num <- NA_real_
    df$age_group <- NA_integer_
  }

  # Gender: coalesce across candidate columns
  gender_cols <- c(demo_map[["gender"]], demo_map[["gender1"]], demo_map[["female"]])
  gender_cols <- gender_cols[!is.null(gender_cols)]
  gender_cols <- gender_cols[gender_cols %in% names(df)]

  df$female_wt <- NA_real_
  for (gc in gender_cols) {
    vals <- as.character(df[[gc]])
    is_female <- vals %in% c("A woman", "Woman", "Female", "female") |
                 suppressWarnings(as.numeric(vals)) == 1
    is_male <- vals %in% c("A man", "Man", "Male", "male") |
               suppressWarnings(as.numeric(vals)) == 0
    df$female_wt <- ifelse(is.na(df$female_wt) & is_female, 1, df$female_wt)
    df$female_wt <- ifelse(is.na(df$female_wt) & is_male, 0, df$female_wt)
  }

  df
}


# ── Get variable names by role for a specific survey ─────────────────────────

get_role_variables <- function(catalogue, survey_name, role) {
  #' Return variable names with a given role in a specific survey.
  #'
  #' @param catalogue List from load_catalogue()
  #' @param survey_name Character, e.g. "Tracking_Survey_-_January_2026"
  #' @param role Character: "attention_check", "demographic", "qc"
  #' @return Character vector of variable names
  smeta <- catalogue$surveys[[survey_name]]
  if (is.null(smeta)) return(character(0))

  roles <- smeta$variable_roles
  if (is.null(roles) || length(roles) == 0) return(character(0))

  # roles is a named list: values are either "role_string" or list(role="...", canonical="...")
  role_types <- sapply(roles, function(r) {
    if (is.list(r)) r$role else r
  })
  matches <- names(roles)[role_types == role]
  return(matches)
}


# ── Clean survey data ────────────────────────────────────────────────────────

clean_survey_data <- function(data, catalogue = NULL, survey_name_col = "survey_name") {
  #' Clean survey data: filter incomplete, screened, failed attention checks.
  #'
  #' For combined datasets with multiple surveys, cleans per-survey because

  #' attention check variable names may differ across surveys.
  #'
  #' @param data Data frame (single survey or combined)
  #' @param catalogue Catalogue list. If NULL, uses default attention check names.
  #' @param survey_name_col Column identifying which survey each row belongs to
  #' @return Cleaned data frame

  n_before <- nrow(data)

  # ── Filter by completion status ──────────────────────────────────────────
  if ("Finished" %in% names(data)) {
    data <- data %>%
      mutate(
        Finished = case_when(
          Finished %in% c("TRUE", "True", "true", "1") ~ 1,
          Finished %in% c("FALSE", "False", "false", "0") ~ 0,
          TRUE ~ suppressWarnings(as.numeric(Finished))
        )
      ) %>%
      filter(Finished != 0)
  }

  # ── Filter screened out ──────────────────────────────────────────────────
  if ("Q_TerminateFlag" %in% names(data)) {
    data <- data %>%
      mutate(
        screenedOut = ifelse(Q_TerminateFlag %in% c("Screened", "QuotaMet"), 1, 0)
      ) %>%
      filter(screenedOut != 1) %>%
      select(-screenedOut)
  }

  # ── Filter by attention checks ───────────────────────────────────────────
  if (!is.null(catalogue) && survey_name_col %in% names(data)) {
    # Per-survey attention check filtering
    surveys_in_data <- unique(data[[survey_name_col]])
    cleaned_parts <- list()

    for (sname in surveys_in_data) {
      sdf <- data %>% filter(!!sym(survey_name_col) == sname)
      attn_vars <- get_role_variables(catalogue, sname, "attention_check")
      attn_vars <- attn_vars[attn_vars %in% names(sdf)]

      if (length(attn_vars) > 0) {
        for (av in attn_vars) {
          sdf[[av]] <- suppressWarnings(as.numeric(sdf[[av]]))
          # Modal value = "pass" (handles both 0=pass and 1=pass surveys)
          vals <- sdf[[av]][!is.na(sdf[[av]])]
          if (length(vals) > 0) {
            pass_val <- as.numeric(names(sort(table(vals), decreasing = TRUE))[1])
            sdf <- sdf %>% filter(is.na(!!sym(av)) | !!sym(av) == pass_val)
          }
        }
      }
      cleaned_parts[[sname]] <- sdf
    }
    data <- bind_rows(cleaned_parts)
  } else {
    # Fallback: try common attention check column names
    default_attn <- c("attnchk1", "attnchk2", "attnchk3",
                       "attention_check", "attention_check1", "attention_check2",
                       "attentioncheck",
                       "vig1_attention_check", "vig2_attention_check",
                       "vig3_attention_check")
    for (av in default_attn) {
      if (av %in% names(data)) {
        data[[av]] <- suppressWarnings(as.numeric(data[[av]]))
        vals <- data[[av]][!is.na(data[[av]])]
        if (length(vals) > 0) {
          pass_val <- as.numeric(names(sort(table(vals), decreasing = TRUE))[1])
          data <- data %>% filter(is.na(!!sym(av)) | !!sym(av) == pass_val)
        }
      }
    }
  }

  # ── Deduplicate by PID ──────────────────────────────────────────────────
  if ("PID" %in% names(data)) {
    data <- data %>%
      arrange(PID, desc(EndDate)) %>%
      group_by(PID) %>%
      slice(1) %>%
      ungroup()
  }

  n_after <- nrow(data)
  message(sprintf("Cleaning: %s -> %s rows (%s removed, %.1f%%)",
                  format(n_before, big.mark = ","),
                  format(n_after, big.mark = ","),
                  format(n_before - n_after, big.mark = ","),
                  (n_before - n_after) / n_before * 100))

  return(data)
}


# ── Weight survey data ───────────────────────────────────────────────────────

weight_survey_data <- function(data, catalogue = NULL, survey_name_col = "survey_name",
                               method = "rake",
                               weights_lookup = NULL) {
  #' Apply survey weights. Tries pre-computed lookup first, falls back to

  #' on-the-fly computation.
  #'
  #' @param data Data frame with province, gender/gender1, age columns
  #' @param catalogue Catalogue list (currently unused, reserved for future use)
  #' @param survey_name_col Column identifying which survey each row belongs to
  #' @param method Weighting method: "rake" (default), "poststrat", or "none"
  #' @param weights_lookup Path to pre-computed weights CSV, or NULL to auto-detect.
  #'   Set to FALSE to skip lookup and always compute on-the-fly.
  #' @return Data frame with added 'wt' column

  if (method == "none") {
    data$wt <- 1
    return(data)
  }

  # ── Try pre-computed weights lookup ────────────────────────────────────
  if (!identical(weights_lookup, FALSE)) {
    lookup_path <- weights_lookup
    if (is.null(lookup_path)) {
      # Auto-detect: look in skill data/ directory
      lookup_path <- tryCatch({
        script_dir <- dirname(sys.frame(sys.nframe())$ofile)
        normalizePath(file.path(script_dir, "..", "data", "weights.csv"), mustWork = FALSE)
      }, error = function(e) NULL)
    }

    if (!is.null(lookup_path) && file.exists(lookup_path)) {
      wt_col <- paste0("wt_", method)
      lookup <- tryCatch(
        read.csv(lookup_path, stringsAsFactors = FALSE),
        error = function(e) NULL
      )

      if (!is.null(lookup) && wt_col %in% names(lookup) &&
          "survey_name" %in% names(lookup) && "ResponseId" %in% names(lookup)) {

        # Check coverage: what % of our data has a lookup match?
        lookup_subset <- lookup %>%
          select(survey_name, ResponseId, wt = !!sym(wt_col))

        matched <- data %>%
          left_join(lookup_subset, by = c(setNames("survey_name", survey_name_col), "ResponseId"))

        hit_rate <- mean(!is.na(matched$wt))
        if (hit_rate > 0.5) {
          matched$wt[is.na(matched$wt)] <- 1
          message(sprintf("Pre-computed weights (%s): %.1f%% matched, %d rows",
                          method, hit_rate * 100, nrow(matched)))
          message(sprintf("Weights: mean=%.3f, min=%.3f, max=%.3f, sd=%.3f",
                          mean(matched$wt, na.rm = TRUE),
                          min(matched$wt, na.rm = TRUE),
                          max(matched$wt, na.rm = TRUE),
                          sd(matched$wt, na.rm = TRUE)))
          return(matched)
        } else {
          message(sprintf("Pre-computed weights: only %.1f%% matched, falling back to on-the-fly", hit_rate * 100))
        }
      }
    }
  }

  # ── On-the-fly computation (original logic) ────────────────────────────

  # ── Ensure demographic columns exist ────────────────────────────────────
  if (!"province" %in% names(data)) {
    warning("No 'province' column found — cannot compute weights. Returning data with wt=1.")
    data$wt <- 1
    return(data)
  }

  # Check for any gender column
  if (!any(c("gender", "gender1", "female") %in% names(data))) {
    warning("No gender column found — cannot compute weights. Returning data with wt=1.")
    data$wt <- 1
    return(data)
  }

  if (!"age" %in% names(data)) {
    warning("No 'age' column found — cannot compute weights. Returning data with wt=1.")
    data$wt <- 1
    return(data)
  }

  # ── Recode demographics (using shared helpers) ──────────────────────────

  data <- data %>%
    mutate(
      province_num = suppressWarnings(as.numeric(province)),
      province_num = ifelse(is.na(province_num),
                            province_text_map[as.character(province)],
                            province_num),
      age = suppressWarnings(as.numeric(age)),
      region = province_to_region(province_num),
      age_group = case_when(
        age <= 34 ~ 1,
        age <= 54 ~ 2,
        age >= 55 ~ 3,
        TRUE ~ NA_real_
      )
    )

  # Gender: handle numeric (0/1), text ("A man"/"A woman"), or gender1 column
  # Coalesce across candidate columns: for each row, use the first non-empty value
  gender_candidates <- c("gender", "gender1", "female")
  gender_candidates <- gender_candidates[gender_candidates %in% names(data)]
  if (length(gender_candidates) > 0) {
    data$.gender_merged <- NA_character_
    for (gc in gender_candidates) {
      vals <- as.character(data[[gc]])
      fill <- is.na(data$.gender_merged) & !is.na(vals) & vals != ""
      data$.gender_merged[fill] <- vals[fill]
    }
    gender_col <- ".gender_merged"
  } else {
    gender_col <- NULL
  }

  if (!is.null(gender_col)) {
    data <- data %>%
      mutate(
        female_wt = case_when(
          !!sym(gender_col) %in% c("A woman", "Woman", "Female", "female") ~ 1,
          !!sym(gender_col) %in% c("A man", "Man", "Male", "male") ~ 0,
          suppressWarnings(as.numeric(!!sym(gender_col))) == 1 ~ 1,
          suppressWarnings(as.numeric(!!sym(gender_col))) == 0 ~ 0,
          TRUE ~ NA_real_
        )
      )
  } else {
    warning("No gender column found — cannot compute weights. Returning data with wt=1.")
    data$wt <- 1
    return(data)
  }

  # ── Weight per survey ──────────────────────────────────────────────────
  weight_one_survey <- function(sdf) {
    # Filter to rows with complete demographics
    sdf_complete <- sdf %>%
      filter(!is.na(region), !is.na(age_group), !is.na(female_wt))

    if (nrow(sdf_complete) < 20) {
      message("  Too few complete cases for weighting (", nrow(sdf_complete), "). Using wt=1.")
      sdf$wt <- 1
      return(sdf)
    }

    split_regions <- sdf_complete %>% split(.$region)

    weighted_list <- map2(split_regions, names(split_regions), function(df_reg, reg) {
      if (nrow(df_reg) < 5 || !reg %in% names(ref_dists)) {
        df_reg$wt_region <- 1
        df_reg$wt <- 1
        return(df_reg)
      }

      # Check that both gender levels exist
      if (length(unique(df_reg$female_wt)) < 2) {
        df_reg$wt_region <- 1
        df_reg$wt <- 1
        return(df_reg)
      }

      tryCatch({
        design <- svydesign(ids = ~1, data = df_reg, weights = NULL)

        gender.dist <- tibble(female_wt = c(0, 1),
                              Freq = nrow(df_reg) * ref_dists[[reg]]$gender)
        age.dist <- tibble(age_group = c(1, 2, 3),
                           Freq = nrow(df_reg) * ref_dists[[reg]]$age)

        rake_res <- rake(
          design,
          sample.margins = list(~female_wt, ~age_group),
          population.margins = list(gender.dist, age.dist)
        )

        rake_res <- trimWeights(rake_res, lower = 0.1, upper = 8, strict = TRUE)
        df_reg$wt_region <- weights(rake_res)

        # Scale to national population share
        region_factor <- region_pop_share[reg] / mean(region_pop_share)
        df_reg$wt <- df_reg$wt_region * region_factor

        df_reg
      }, error = function(e) {
        message("  Raking failed for region ", reg, ": ", e$message, ". Using wt=1.")
        df_reg$wt_region <- 1
        df_reg$wt <- 1
        df_reg
      })
    })

    weighted_combined <- bind_rows(weighted_list)

    # Join weights back to full survey data (including incomplete demographics)
    sdf <- sdf %>%
      left_join(
        weighted_combined %>% select(any_of(c("ResponseId", "wt"))),
        by = "ResponseId"
      ) %>%
      mutate(wt = ifelse(is.na(wt), 1, wt))

    sdf
  }

  if (survey_name_col %in% names(data)) {
    surveys <- unique(data[[survey_name_col]])
    weighted_parts <- list()
    for (sname in surveys) {
      message("Weighting: ", sname)
      sdf <- data %>% filter(!!sym(survey_name_col) == sname)
      weighted_parts[[sname]] <- weight_one_survey(sdf)
    }
    data <- bind_rows(weighted_parts)
  } else {
    data <- weight_one_survey(data)
  }

  # Clean up intermediate columns
  data <- data %>% select(-any_of(c("region", "age_group", "female_wt", "wt_region", "province_num")))

  # Report
  if ("wt" %in% names(data)) {
    message(sprintf("Weights: mean=%.3f, min=%.3f, max=%.3f, sd=%.3f",
                    mean(data$wt, na.rm = TRUE),
                    min(data$wt, na.rm = TRUE),
                    max(data$wt, na.rm = TRUE),
                    sd(data$wt, na.rm = TRUE)))
  }

  return(data)
}

